'use client'

import { useEffect, useState } from 'react'
import { motion } from 'framer-motion'
import { ArrowRight, MessageCircle, CheckCircle } from 'lucide-react'
import GlowButton from '@/components/ui/GlowButton'
import { siteConfig, heroTrust } from '@/lib/data'

const chatMessages = [
  { from: 'lead', text: 'Olá, tenho interesse num BMW Série 3', time: '23:47' },
  { from: 'agent', text: 'Olá! Que orçamento tem em mente para este BMW?', time: '23:47' },
  { from: 'lead', text: 'Até 28.000€', time: '23:48' },
  { from: 'agent', text: 'Temos 3 opções disponíveis. Prefere novo ou usado?', time: '23:48' },
  { from: 'lead', text: 'Usado, com menos de 80.000 km', time: '23:49' },
]

function AgentDemo() {
  const [visibleMessages, setVisibleMessages] = useState(0)

  useEffect(() => {
    const interval = setInterval(() => {
      setVisibleMessages((v) => {
        if (v >= chatMessages.length) {
          clearInterval(interval)
          return v
        }
        return v + 1
      })
    }, 900)
    return () => clearInterval(interval)
  }, [])

  return (
    <div className="relative w-full max-w-sm mx-auto lg:mx-0 lg:ml-auto">
      {/* Glow behind card */}
      <div className="absolute inset-0 blur-3xl bg-blue-600/20 rounded-3xl scale-110" />

      <div className="relative glass-card rounded-2xl p-5 border border-white/10">
        {/* Header */}
        <div className="flex items-center gap-3 mb-5 pb-4 border-b border-white/[0.06]">
          <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-blue-600 to-cyan-500 flex items-center justify-center">
            <span className="text-xs font-bold text-white">AZ</span>
          </div>
          <div>
            <p className="text-sm font-semibold text-white">ATZ Agent</p>
            <div className="flex items-center gap-1.5">
              <span className="glow-dot w-2 h-2" />
              <span className="text-xs text-slate-400">Ativo • Lead recebido</span>
            </div>
          </div>
          <div className="ml-auto text-right">
            <p className="text-xs text-slate-500">23:47</p>
            <p className="text-xs text-green-400 font-medium">0.4s resposta</p>
          </div>
        </div>

        {/* Messages */}
        <div className="space-y-3 min-h-[180px]">
          {chatMessages.slice(0, visibleMessages).map((msg, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, y: 10, scale: 0.96 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              transition={{ duration: 0.3 }}
              className={`flex ${msg.from === 'agent' ? 'justify-start' : 'justify-end'}`}
            >
              <div
                className={`max-w-[80%] px-3.5 py-2 rounded-2xl text-xs leading-relaxed ${
                  msg.from === 'agent'
                    ? 'bg-blue-600/20 text-blue-100 rounded-tl-sm border border-blue-500/20'
                    : 'bg-white/[0.07] text-slate-300 rounded-tr-sm'
                }`}
              >
                {msg.text}
              </div>
            </motion.div>
          ))}
        </div>

        {/* Score Footer */}
        {visibleMessages >= chatMessages.length && (
          <motion.div
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            className="mt-4 pt-4 border-t border-white/[0.06] flex items-center justify-between"
          >
            <div className="flex items-center gap-2">
              <span className="text-xs text-slate-400">Score Lead:</span>
              <span className="px-2.5 py-1 bg-green-500/15 text-green-400 text-xs font-bold rounded-lg border border-green-500/20">
                HOT · 91
              </span>
            </div>
            <span className="text-xs text-slate-500">→ João Silva</span>
          </motion.div>
        )}
      </div>
    </div>
  )
}

function BackgroundBlobs() {
  return (
    <div className="absolute inset-0 overflow-hidden pointer-events-none" aria-hidden>
      <div className="absolute -top-40 -left-40 w-[700px] h-[700px] rounded-full bg-blue-700/10 blur-[120px] animate-blob-1" />
      <div className="absolute -bottom-40 -right-20 w-[600px] h-[600px] rounded-full bg-violet-700/8 blur-[100px] animate-blob-2" />
      <div className="absolute top-1/2 left-1/3 w-[400px] h-[400px] rounded-full bg-cyan-700/6 blur-[80px] animate-blob-3" />
      <div
        className="absolute inset-0 opacity-[0.03]"
        style={{
          backgroundImage:
            'radial-gradient(circle, rgba(255,255,255,0.8) 1px, transparent 1px)',
          backgroundSize: '32px 32px',
        }}
      />
    </div>
  )
}

const containerVariants = {
  hidden: {},
  show: {
    transition: { staggerChildren: 0.12, delayChildren: 0.2 },
  },
}

const itemVariants = {
  hidden: { opacity: 0, y: 24 },
  show: { opacity: 1, y: 0, transition: { duration: 0.7, ease: [0.16, 1, 0.3, 1] } },
}

export default function Hero() {
  return (
    <section className="relative min-h-screen flex flex-col justify-center overflow-hidden bg-bg-base pt-20">
      <BackgroundBlobs />

      <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16 lg:py-24">
        <div className="grid lg:grid-cols-2 gap-12 lg:gap-16 items-center">
          {/* Left — Content */}
          <motion.div
            variants={containerVariants}
            initial="hidden"
            animate="show"
            className="space-y-7"
          >
            {/* Label */}
            <motion.div variants={itemVariants}>
              <div className="inline-flex items-center gap-2 px-3.5 py-1.5 rounded-full border border-blue-500/20 bg-blue-500/8 text-blue-400 text-xs font-semibold tracking-widest uppercase">
                <span className="glow-dot w-2 h-2" />
                ATZ Agent · Para Stands Automóveis
              </div>
            </motion.div>

            {/* Headline */}
            <motion.div variants={itemVariants}>
              <h1 className="font-display text-5xl sm:text-6xl lg:text-[68px] font-bold leading-[1.06] tracking-tight">
                <span className="text-white">Automatize o Seu</span>
                <br />
                <span className="text-white">Stand Automóvel</span>
                <br />
                <span className="text-gradient-brand">com IA</span>
              </h1>
            </motion.div>

            {/* Sub */}
            <motion.div variants={itemVariants}>
              <p className="text-xl text-slate-300 font-medium">
                Qualifique Leads 24/7 em Portugal
              </p>
            </motion.div>

            {/* Main Message */}
            <motion.div variants={itemVariants}>
              <p className="text-base text-slate-400 leading-relaxed max-w-xl">
                {siteConfig.mainMessage}
              </p>
            </motion.div>

            {/* CTAs */}
            <motion.div variants={itemVariants} className="flex flex-wrap gap-3">
              <GlowButton
                variant="whatsapp"
                size="lg"
                href={siteConfig.whatsapp}
                icon={<MessageCircle size={18} />}
              >
                Falar connosco no WhatsApp
              </GlowButton>
              <GlowButton
                variant="outline"
                size="lg"
                href="#funcionalidades"
                icon={<ArrowRight size={18} />}
              >
                Ver como funciona
              </GlowButton>
            </motion.div>

            {/* Trust items */}
            <motion.div
              variants={itemVariants}
              className="flex flex-wrap items-center gap-x-4 gap-y-2"
            >
              {heroTrust.map((item, i) => (
                <div key={i} className="flex items-center gap-1.5 text-xs text-slate-500">
                  <CheckCircle size={12} className="text-blue-500 flex-shrink-0" />
                  {item}
                </div>
              ))}
            </motion.div>
          </motion.div>

          {/* Right — Agent Demo */}
          <motion.div
            initial={{ opacity: 0, x: 40 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.9, delay: 0.4, ease: [0.16, 1, 0.3, 1] }}
          >
            <AgentDemo />
          </motion.div>
        </div>

        {/* Stats Row */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.8 }}
          className="mt-20 grid grid-cols-2 lg:grid-cols-4 gap-px bg-white/[0.05] rounded-2xl overflow-hidden border border-white/[0.06]"
        >
          {[
            { value: '100+', label: 'Leads/dia em stands médios' },
            { value: '30–40%', label: 'Leads sem resposta em 24h' },
            { value: '7×', label: 'Mais conversões <1h resposta' },
            { value: '6h/dia', label: 'Gastas só a responder' },
          ].map((stat, i) => (
            <div key={i} className="bg-bg-base/80 px-6 py-5 text-center">
              <p className="font-display text-2xl font-bold text-gradient-brand mb-1">
                {stat.value}
              </p>
              <p className="text-xs text-slate-500 leading-tight">{stat.label}</p>
            </div>
          ))}
        </motion.div>
      </div>

      {/* Bottom fade */}
      <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-bg-base to-transparent pointer-events-none" />
    </section>
  )
}
